import React, { useState, useEffect } from 'react';
import { Navigation } from './components/Navigation';
import { Hero } from './components/Hero';
import { ContentSections } from './components/ContentSections';
import { ProjectGrid } from './components/ProjectGrid';
import { ContactSection } from './components/ContactSection';
import { ThemeToggle } from './components/ThemeToggle';
import { USER_INFO } from './constants';

function App() {
  const [theme, setTheme] = useState<'light' | 'dark'>('light');

  useEffect(() => {
    // Check local storage or system preference on mount
    const savedTheme = localStorage.getItem('theme') as 'light' | 'dark' | null;
    const systemPrefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;

    if (savedTheme) {
      setTheme(savedTheme);
    } else if (systemPrefersDark) {
      setTheme('dark');
    }
  }, []);

  useEffect(() => {
    // Apply theme class to html element
    const root = window.document.documentElement;
    if (theme === 'dark') {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
    localStorage.setItem('theme', theme);
  }, [theme]);

  const toggleTheme = () => {
    setTheme(prev => prev === 'light' ? 'dark' : 'light');
  };

  return (
    <div className="relative w-full overflow-hidden bg-[#fcfcfc] dark:bg-[#050505] transition-colors duration-500">
      <Navigation />

      <main>
        <Hero />
        <ContentSections />
        <ProjectGrid />
        <ContactSection />
      </main>

      <footer className="py-8 border-t border-neutral-200 dark:border-neutral-800 text-center">
        <p className="text-xs text-neutral-400 font-mono uppercase tracking-widest">
          &copy; {new Date().getFullYear()} {USER_INFO.name}. All Rights Reserved.
        </p>
      </footer>

      {/* Floating Theme Toggle */}
      <ThemeToggle isDark={theme === 'dark'} toggleTheme={toggleTheme} />
    </div>
  );
}

