           <h2 className="text-6xl md:text-7xl lg:text-8xl font-serif text-neutral-900 dark:text-white leading-[0.9] mb-8">
             Let's<br/>Talk.
           </h2>
           <div className="space-y-6 text-neutral-600 dark:text-neutral-400">
             <div>
                <p className="text-sm font-mono text-brand-600 dark:text-brand-400 mb-1">EMAIL</p>
                <a href={`mailto:${USER_INFO.email}`} className="text-xl hover:text-black dark:hover:text-white transition-colors">{USER_INFO.email}</a>
             </div>
             <div>
                <p className="text-sm font-mono text-brand-600 dark:text-brand-400 mb-1">PHONE</p>
                <p className="text-xl">{USER_INFO.phone}</p>
             </div>
           </div>
        </div>

        {/* Form */}
        <div className="md:col-span-7 md:pl-12 relative min-h-[400px]">
            <form className="space-y-12" onSubmit={handleSubmit}>
              <div className="group">
                <input 
                  type="text" 
                  name="name"
                  required
                  className="w-full bg-transparent border-b border-neutral-300 dark:border-neutral-700 py-4 text-xl text-neutral-900 dark:text-white focus:outline-none focus:border-brand-600 dark:focus:border-brand-400 transition-colors placeholder-transparent"
                  placeholder="Name"
                  id="name"
                />
                <label htmlFor="name" className="block text-sm font-mono text-neutral-400 mt-2 uppercase tracking-widest group-focus-within:text-brand-600 dark:group-focus-within:text-brand-400 transition-colors">Your Name</label>
              </div>

              <div className="group">
                <input 
                  type="email" 
                  name="email"
                  required
                  className="w-full bg-transparent border-b border-neutral-300 dark:border-neutral-700 py-4 text-xl text-neutral-900 dark:text-white focus:outline-none focus:border-brand-600 dark:focus:border-brand-400 transition-colors placeholder-transparent"
                  placeholder="Email"
                  id="email"
                />
                <label htmlFor="email" className="block text-sm font-mono text-neutral-400 mt-2 uppercase tracking-widest group-focus-within:text-brand-600 dark:group-focus-within:text-brand-400 transition-colors">Your Email</label>
              </div>

              <div className="group">
                <textarea 
                  name="message"
                  required
                  rows={3}
                  className="w-full bg-transparent border-b border-neutral-300 dark:border-neutral-700 py-4 text-xl text-neutral-900 dark:text-white focus:outline-none focus:border-brand-600 dark:focus:border-brand-400 transition-colors resize-none placeholder-transparent"
                  placeholder="Message"
                  id="message"
                />
                <label htmlFor="message" className="block text-sm font-mono text-neutral-400 mt-2 uppercase tracking-widest group-focus-within:text-brand-600 dark:group-focus-within:text-brand-400 transition-colors">Your Message</label>
              </div>

              {errorMessage && (
                <div className="flex items-center space-x-2 text-red-500 bg-red-50 dark:bg-red-900/20 p-4 rounded-sm">
                  <AlertCircle size={20} />
                  <span className="text-sm font-medium">{errorMessage}</span>
                </div>
              )}

              <button 
                type="submit"
                disabled={isSubmitting}
                className="group flex items-center justify-center space-x-2 px-10 py-4 bg-neutral-900 dark:bg-white text-white dark:text-neutral-900 text-sm uppercase tracking-widest hover:bg-brand-600 dark:hover:bg-brand-200 transition-all duration-300 hover:px-12 disabled:opacity-70 disabled:hover:px-10 disabled:cursor-not-allowed w-full md:w-auto"
              >
                {isSubmitting ? (
                  <>
                    <Loader2 className="w-4 h-4 animate-spin" />
                    <span>Sending...</span>
                  </>
                ) : (
                  <span>Send Message</span>
                )}
              </button>
            </form>
        </div>
      </div>

      {/* Success Modal Popup */}
      <AnimatePresence>
        {isSuccess && (
          <motion.div 
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm"
          >
            <motion.div 
              initial={{ scale: 0.9, y: 20, opacity: 0 }}
              animate={{ scale: 1, y: 0, opacity: 1 }}
              exit={{ scale: 0.9, y: 20, opacity: 0 }}
              className="bg-white dark:bg-neutral-800 p-8 rounded-lg shadow-2xl max-w-sm w-full text-center border border-neutral-100 dark:border-neutral-700 relative"
            >
              <button 
                onClick={() => setIsSuccess(false)}
                className="absolute top-4 right-4 text-neutral-400 hover:text-neutral-900 dark:hover:text-white transition-colors"
              >
                <X size={20} />
              </button>

              <div className="w-16 h-16 bg-green-100 dark:bg-green-900/30 rounded-full flex items-center justify-center mx-auto mb-6">
                <CheckCircle2 className="w-8 h-8 text-green-600 dark:text-green-400" />
              </div>

              <h3 className="text-2xl font-serif text-neutral-900 dark:text-white mb-2">Message Sent!</h3>
              <p className="text-neutral-500 dark:text-neutral-400 mb-8">
                Thank you for reaching out. I'll get back to you as soon as possible.
              </p>

              <button 
                onClick={() => setIsSuccess(false)}
                className="w-full py-3 bg-neutral-900 dark:bg-white text-white dark:text-neutral-900 font-bold uppercase tracking-widest hover:bg-brand-600 dark:hover:bg-brand-200 transition-colors rounded-sm"
              >
                Close
              </button>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </SectionWrapper>
  );
};

