                                {USER_INFO.email}
                             </a>
                             <button 
                                onClick={handleCopy} 
                                className="p-1.5 text-slate-400 hover:text-brand-500 hover:bg-brand-50 dark:hover:bg-slate-800 rounded-md transition-all relative"
                                title="Copy Email"
                             >
                                {copied ? <Check size={18} className="text-green-500" /> : <Copy size={18} />}
                             </button>
                        </div>
                    </div>
                </div>

                {/* Phone */}
                <div className="flex items-start gap-4 group">
                    <div className="w-12 h-12 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg flex items-center justify-center flex-shrink-0 text-brand-600 dark:text-brand-400 group-hover:bg-brand-600 group-hover:text-white transition-colors duration-300">
